                    <div style="display: grid; grid-template-columns: repeat(4, 1fr); gap: 5px;">
                        ${['7','8','9','/','4','5','6','*','1','2','3','-','0','.','=','+'].map(btn => 
                            `<button class="hacking-button" onclick="hackingTool.calcBtn('${btn}')">${btn}</button>`
                        ).join('')}
                        <button class="hacking-button" onclick="hackingTool.calcBtn('C')" style="grid-column: span 4;">C</button>
                    </div>
