        calcBtn(btn) {
            const display = document.getElementById('calcDisplay');
            
            if (btn === 'C') {
                this.calcValue = '0';
            } else if (btn === '=') {
                try {
                    this.calcValue = eval(this.calcValue).toString();
                    if (this.calcValue === '1337') {
                        setTimeout(() => {
                            alert('🎉 ¡Encontraste el número mágico! ¡Eres un verdadero hacker!');
                            this.showSecretMessage();
                        }, 100);
                    }
                } catch (e) {
                    this.calcValue = 'Error';
                }
            } else {
                if (this.calcValue === '0' || this.calcValue === 'Error') {
                    this.calcValue = btn;
                } else {
                    this.calcValue += btn;
                }
            }
            
            display.value = this.calcValue;
        },

